const ahora = new Date();

// Ajustar a zona Guayaquil (UTC-5)
const offsetGuayaquil = -5 * 60;
const utcMs = ahora.getTime() + ahora.getTimezoneOffset() * 60000;
const localMs = utcMs + offsetGuayaquil * 60000;
const hoy = new Date(localMs);

const diasNombre = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
const mesesNombre = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

function toISO(d) {
  const y = d.getFullYear();
  const m = String(d.getMonth()+1).padStart(2,'0');
  const day = String(d.getDate()).padStart(2,'0');
  return `${y}-${m}-${day}`;
}

function sumar(d, dias) {
  const r = new Date(d);
  r.setDate(r.getDate() + dias);
  return r;
}

// Próximo día de semana (0=dom, 1=lun...)
function proximoDia(diaObjetivo) {
  const hoyNum = hoy.getDay();
  let diff = diaObjetivo - hoyNum;
  if (diff <= 0) diff += 7;
  return sumar(hoy, diff);
}

const manana = sumar(hoy, 1);
const pasado = sumar(hoy, 2);

// Esta semana (próxima ocurrencia de cada día)
const lunes     = proximoDia(1);
const martes    = proximoDia(2);
const miercoles = proximoDia(3);
const jueves    = proximoDia(4);
const viernes   = proximoDia(5);
const sabado    = proximoDia(6);
const domingo   = proximoDia(0);

const item = $input.first();

return [{
  json: {
    ...item.json,
    fechaHoy:     toISO(hoy),
    fechaTexto:   `${diasNombre[hoy.getDay()]} ${hoy.getDate()} de ${mesesNombre[hoy.getMonth()]} de ${hoy.getFullYear()}`,
    manana:       toISO(manana),
    mananaTexto:  `${diasNombre[manana.getDay()]} ${manana.getDate()} de ${mesesNombre[manana.getMonth()]}`,
    pasadomanana: toISO(pasado),

    lunes:     toISO(lunes),
    martes:    toISO(martes),
    miercoles: toISO(miercoles),
    jueves:    toISO(jueves),
    viernes:   toISO(viernes),
    sabado:    toISO(sabado),
    domingo:   toISO(domingo),

    lunes_proxima:     toISO(sumar(lunes, 7)),
    martes_proxima:    toISO(sumar(martes, 7)),
    miercoles_proxima: toISO(sumar(miercoles, 7)),
    jueves_proxima:    toISO(sumar(jueves, 7)),
    viernes_proxima:   toISO(sumar(viernes, 7)),
    sabado_proxima:    toISO(sumar(sabado, 7)),
    domingo_proxima:   toISO(sumar(domingo, 7)),
  }
}];

